// conformance/src/bench/mod.rs

use std::time::{Duration, Instant};
use serde::{Serialize, Deserialize};

/// A benchmark definition.
pub struct Benchmark {
    /// Unique identifier.
    pub id: &'static str,
    /// Human-readable name.
    pub name: &'static str,
    /// What this benchmark measures.
    pub description: &'static str,
    /// Category for grouping.
    pub category: BenchCategory,
    /// Number of warmup iterations.
    pub warmup: u32,
    /// Number of measurement iterations.
    pub iterations: u32,
    /// The benchmark function.
    pub bench_fn: Box<dyn Fn(&dyn ConformanceRuntime) -> Duration + Send + Sync>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum BenchCategory {
    TaskSpawn,      // Task creation overhead
    TaskSwitch,     // Context switch latency
    ChannelThroughput,
    ChannelLatency,
    MutexContention,
    TimerAccuracy,
    IoThroughput,
    IoLatency,
}

/// Macro for defining benchmarks.
#[macro_export]
macro_rules! benchmark {
    (
        id: $id:literal,
        name: $name:literal,
        description: $desc:literal,
        category: $cat:expr,
        warmup: $warmup:expr,
        iterations: $iters:expr,
        bench: |$rt:ident| $body:expr
    ) => {
        Benchmark {
            id: $id,
            name: $name,
            description: $desc,
            category: $cat,
            warmup: $warmup,
            iterations: $iters,
            bench_fn: Box::new(|$rt: &dyn ConformanceRuntime| {
                $body
            }),
        }
    };
}
