### Step 2: Statistics Computation

```rust
// conformance/src/bench/stats.rs

/// Statistical summary of benchmark results.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Stats {
    pub min: Duration,
    pub max: Duration,
    pub mean: Duration,
    pub median: Duration,
    pub std_dev: Duration,
    pub p50: Duration,
    pub p75: Duration,
    pub p90: Duration,
    pub p95: Duration,
    pub p99: Duration,
    pub p999: Duration,
}

impl Stats {
    pub fn from_samples(samples: &[Duration]) -> Self {
        let mut sorted: Vec<_> = samples.to_vec();
        sorted.sort();

        let n = sorted.len();
        let sum: Duration = sorted.iter().sum();
        let mean = sum / n as u32;

        let variance: f64 = sorted.iter()
            .map(|d| {
                let diff = d.as_nanos() as f64 - mean.as_nanos() as f64;
                diff * diff
            })
            .sum::<f64>() / n as f64;
        let std_dev = Duration::from_nanos(variance.sqrt() as u64);

        Self {
            min: sorted[0],
            max: sorted[n - 1],
            mean,
            median: sorted[n / 2],
            std_dev,
            p50: sorted[n * 50 / 100],
            p75: sorted[n * 75 / 100],
            p90: sorted[n * 90 / 100],
            p95: sorted[n * 95 / 100],
            p99: sorted[n * 99 / 100],
            p999: sorted[n * 999 / 1000],
        }
    }

    /// Coefficient of variation (std_dev / mean).
    pub fn cv(&self) -> f64 {
        self.std_dev.as_nanos() as f64 / self.mean.as_nanos() as f64
    }
}

/// Comparison between two implementations.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Comparison {
    pub asupersync: Stats,
    pub tokio: Stats,
    pub speedup: f64,  // tokio.mean / asupersync.mean (>1 = we're faster)
    pub confidence: ComparisonConfidence,
}

#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub enum ComparisonConfidence {
    High,      // Clear winner, low variance
    Medium,    // Likely winner, some variance
    Low,       // Too close to call
    Uncertain, // High variance, unreliable
}

impl Comparison {
    pub fn compute(asupersync: &Stats, tokio: &Stats) -> Self {
        let speedup = tokio.mean.as_nanos() as f64 / asupersync.mean.as_nanos() as f64;

        // Determine confidence based on coefficient of variation and difference
        let avg_cv = (asupersync.cv() + tokio.cv()) / 2.0;
        let diff_pct = (speedup - 1.0).abs();

        let confidence = if avg_cv > 0.5 {
            ComparisonConfidence::Uncertain
        } else if diff_pct < 0.05 {
            ComparisonConfidence::Low
        } else if avg_cv > 0.2 {
            ComparisonConfidence::Medium
        } else {
            ComparisonConfidence::High
        };

        Self {
            asupersync: asupersync.clone(),
            tokio: tokio.clone(),
            speedup,
            confidence,
        }
    }
}
```

### Step 3: Benchmark Runner

```rust
// conformance/src/bench/runner.rs

use tracing::{info, debug, span, Level};

/// Benchmark runner configuration.
pub struct BenchConfig {
    pub warmup_multiplier: f32,  // Extra warmup beyond benchmark spec
    pub min_samples: u32,        // Minimum samples regardless of spec
    pub max_time: Duration,      // Max time per benchmark
    pub output: BenchOutput,
}

#[derive(Debug, Clone)]
pub enum BenchOutput {
    Console,
    Json(PathBuf),
    Html(PathBuf),
    All { json: PathBuf, html: PathBuf },
}

/// Benchmark runner.
pub struct BenchRunner {
    asupersync: AsupersyncRuntime,
    tokio: TokioRuntime,
    config: BenchConfig,
    results: Vec<BenchResult>,
}

#[derive(Debug, Serialize)]
pub struct BenchResult {
    pub benchmark_id: String,
    pub benchmark_name: String,
    pub category: BenchCategory,
    pub asupersync_samples: Vec<Duration>,
    pub tokio_samples: Vec<Duration>,
    pub comparison: Comparison,
}

impl BenchRunner {
    pub fn new(config: BenchConfig) -> Self {
        Self {
            asupersync: AsupersyncRuntime::new(),
            tokio: TokioRuntime::new(),
            config,
            results: Vec::new(),
        }
    }

    pub fn run_all(&mut self, benchmarks: &[Benchmark]) -> BenchSummary {
        info!(count = benchmarks.len(), "Running benchmarks");

        for bench in benchmarks {
            let result = self.run_benchmark(bench);
            self.results.push(result);
        }

        self.generate_summary()
    }

    fn run_benchmark(&self, bench: &Benchmark) -> BenchResult {
        let span = span!(Level::INFO, "bench", id = bench.id);
        let _guard = span.enter();

        info!(name = bench.name, "Starting benchmark");

        // Warmup phase
        debug!(iterations = bench.warmup, "Running warmup");
        for _ in 0..bench.warmup {
            (bench.bench_fn)(&self.asupersync);
            (bench.bench_fn)(&self.tokio);
        }

        // Measurement phase - asupersync
        debug!(iterations = bench.iterations, "Measuring asupersync");
        let asupersync_samples: Vec<_> = (0..bench.iterations)
            .map(|i| {
                let duration = (bench.bench_fn)(&self.asupersync);
                if i % 100 == 0 {
                    debug!(iteration = i, duration_us = duration.as_micros(), "Sample");
                }
                duration
            })
            .collect();

        // Measurement phase - tokio
        debug!(iterations = bench.iterations, "Measuring tokio");
        let tokio_samples: Vec<_> = (0..bench.iterations)
            .map(|i| {
                let duration = (bench.bench_fn)(&self.tokio);
                if i % 100 == 0 {
                    debug!(iteration = i, duration_us = duration.as_micros(), "Sample");
                }
                duration
            })
            .collect();

        let asupersync_stats = Stats::from_samples(&asupersync_samples);
        let tokio_stats = Stats::from_samples(&tokio_samples);
        let comparison = Comparison::compute(&asupersync_stats, &tokio_stats);

        info!(
            speedup = format!("{:.2}x", comparison.speedup),
            asupersync_mean_us = asupersync_stats.mean.as_micros(),
            tokio_mean_us = tokio_stats.mean.as_micros(),
            confidence = ?comparison.confidence,
            "Benchmark complete"
        );

        BenchResult {
            benchmark_id: bench.id.to_string(),
            benchmark_name: bench.name.to_string(),
            category: bench.category,
            asupersync_samples,
            tokio_samples,
            comparison,
        }
    }
}
