// conformance/src/bench/benchmarks.rs

/// Task spawning throughput benchmark.
benchmark! {
    id: "bench-spawn-001",
    name: "Task spawn throughput",
    description: "Measure task spawn rate (tasks/second)",
    category: BenchCategory::TaskSpawn,
    warmup: 1000,
    iterations: 10000,
    bench: |rt| {
        let start = Instant::now();
        rt.block_on(async {
            let handles: Vec<_> = (0..100)
                .map(|i| rt.spawn(async move { i }))
                .collect();
            join_all(handles).await;
        });
        start.elapsed()
    }
}

/// Channel throughput benchmark.
benchmark! {
    id: "bench-channel-001",
    name: "MPSC channel throughput",
    description: "Messages per second through bounded channel",
    category: BenchCategory::ChannelThroughput,
    warmup: 100,
    iterations: 1000,
    bench: |rt| {
        rt.block_on(async {
            let (tx, mut rx) = rt.mpsc_channel(1000);

            let sender = rt.spawn(async move {
                for i in 0..10_000 {
                    tx.send(i).await.unwrap();
                }
            });

            let start = Instant::now();

            let receiver = rt.spawn(async move {
                let mut count = 0;
                while let Some(_) = rx.recv().await {
                    count += 1;
                }
                count
            });

            drop(sender); // Close channel
            let _ = receiver.await;

            start.elapsed()
        })
    }
}

/// Mutex contention benchmark.
benchmark! {
    id: "bench-mutex-001",
    name: "Mutex contention",
    description: "Lock acquisitions per second under contention",
    category: BenchCategory::MutexContention,
    warmup: 100,
    iterations: 1000,
    bench: |rt| {
        rt.block_on(async {
            let mutex = rt.mutex(0u64);
            let mutex = Arc::new(mutex);

            let start = Instant::now();

            let handles: Vec<_> = (0..10)
                .map(|_| {
                    let mutex = mutex.clone();
                    rt.spawn(async move {
                        for _ in 0..1000 {
                            let mut guard = mutex.lock().await;
                            *guard += 1;
                        }
                    })
                })
                .collect();

            join_all(handles).await;
            start.elapsed()
        })
    }
}

/// Timer accuracy benchmark.
benchmark! {
    id: "bench-timer-001",
    name: "Sleep accuracy",
    description: "Measure actual sleep duration vs requested",
    category: BenchCategory::TimerAccuracy,
    warmup: 100,
    iterations: 1000,
    bench: |rt| {
        rt.block_on(async {
            let requested = Duration::from_millis(1);
            let start = Instant::now();
            rt.sleep(requested).await;
            let actual = start.elapsed();

            // Return the error (deviation from requested)
            if actual > requested {
                actual - requested
            } else {
                requested - actual
            }
        })
    }
}

/// Context switch latency benchmark.
benchmark! {
    id: "bench-switch-001",
    name: "Context switch latency",
    description: "Time for yield-and-resume cycle",
    category: BenchCategory::TaskSwitch,
    warmup: 1000,
    iterations: 10000,
    bench: |rt| {
        rt.block_on(async {
            let start = Instant::now();

            // Yield 100 times
            for _ in 0..100 {
                rt.yield_now().await;
            }

            start.elapsed()
        })
    }
}
