}

pub enum VerificationResult {
    /// Trace satisfies spec
    Valid,

    /// Trace violates invariant at step N
    InvariantViolation { step: usize, invariant: String },

    /// Trace has invalid transition at step N
    InvalidTransition { step: usize, from: TlaState, action: TlaAction },
}
```

## Spec-Guided Testing

Use TLA+ spec to generate test cases:
