### Blocking Pool Handle
```rust
/// Handle for blocking operations on a single connection.
pub struct Handle<T> {
    inner: Arc<Mutex<T>>,
    pool: BlockingPool,
}

impl<T: Send + 'static> Handle<T> {
    /// Execute operation on the connection.
    pub async fn call<F, R>(&self, f: F) -> Outcome<R, SqliteError>
    where
        F: FnOnce(&mut T) -> Result<R, rusqlite::Error> + Send + 'static,
        R: Send + 'static,
    {
        let inner = Arc::clone(&self.inner);
        self.pool.spawn(move || {
            let mut guard = inner.lock().unwrap();
            f(&mut *guard)
        }).await
    }
}
